// Cel-Shaded Outline fragment shader (GLSL/WebGL)
uniform sampler2D tDiffuse;
uniform sampler2D tDepth;
uniform vec2 uResolution;
varying vec2 vUv;

float getDepth(vec2 uv) {
    return texture2D(tDepth, uv).r;
}

void main() {
    vec4 color = texture2D(tDiffuse, vUv);
    float dx = 1.0 / uResolution.x;
    float dy = 1.0 / uResolution.y;

    // Sobel operator for depth edge detection
    float d00 = getDepth(vUv + vec2(-dx, -dy));
    float d10 = getDepth(vUv + vec2(0.0, -dy));
    float d20 = getDepth(vUv + vec2(dx, -dy));
    float d01 = getDepth(vUv + vec2(-dx, 0.0));
    float d21 = getDepth(vUv + vec2(dx, 0.0));
    float d02 = getDepth(vUv + vec2(-dx, dy));
    float d12 = getDepth(vUv + vec2(0.0, dy));
    float d22 = getDepth(vUv + vec2(dx, dy));

    float sx = (d20 + 2.0*d21 + d22) - (d00 + 2.0*d01 + d02);
    float sy = (d02 + 2.0*d12 + d22) - (d00 + 2.0*d10 + d20);
    float edge = sqrt(sx*sx + sy*sy);

    if (edge > 0.02) {
        gl_FragColor = vec4(0.0, 0.0, 0.0, 1.0); // Black outline border
    } else {
        gl_FragColor = color;
    }
}

// Hologram Shader with Scanline Scrolling & Fresnel Reflection
uniform float uTime;
uniform vec3 uColor;
varying vec3 vNormal;
varying vec3 vViewPosition;
varying vec3 vWorldPosition;

void main() {
    vec3 normal = normalize(vNormal);
    vec3 viewDir = normalize(vViewPosition);

    // Fresnel term
    float fresnel = pow(1.0 - saturate(dot(normal, viewDir)), 3.0);

    // Scanlines based on vertical world coordinate
    float scanline = sin(vWorldPosition.y * 30.0 - uTime * 6.0) * 0.5 + 0.5;
    scanline = pow(scanline, 2.0);

    // Flickering
    float flicker = sin(uTime * 100.0) * cos(uTime * 30.0) * 0.05 + 0.95;

    float alpha = (fresnel + scanline * 0.4) * flicker;
    gl_FragColor = vec4(uColor * flicker * 1.5, alpha * 0.7);
}

// Animated Molten Magma / Lava Shader (HLSL for Unity/URP)
fixed4 frag(v2f i) : SV_Target {
    // Animated texture coordinates with scrolling distortion noise
    float2 uvNoise = i.uv * 4.0 + _Time.x * _DistortionSpeed;
    float noiseVal = tex2D(_NoiseTex, uvNoise).r;

    float2 uvFlow1 = i.uv + float2(_Time.y * _FlowSpeed.x, _Time.y * _FlowSpeed.y) + noiseVal * 0.15;
    float2 uvFlow2 = i.uv - float2(_Time.y * _FlowSpeed.y, _Time.y * _FlowSpeed.x) - noiseVal * 0.1;

    float lava1 = tex2D(_MainTex, uvFlow1).r;
    float lava2 = tex2D(_MainTex, uvFlow2).g;

    float combined = saturate(lava1 + lava2);
    fixed4 magmaColor = lerp(_CoolColor, _HotColor, combined * combined);

    // Add procedural heat glow expansion
    magmaColor.rgb += step(0.8, combined) * _GlowIntensity * float3(1.0, 0.4, 0.0);
    return magmaColor;
}

// Dynamic Vertex Sway Wind Wave grass shader (HLSL)
void vert(inout appdata_full v) {
    float4 worldPos = mul(unity_ObjectToWorld, v.vertex);

    // Wind calculations: frequency & amplitude decaying near grass base (v.texcoord.y)
    float wave = sin(worldPos.x * _WindFrequency + _Time.y * _WindSpeed) * cos(worldPos.z * _WindFrequency + _Time.y * _WindSpeed);
    float heightFactor = v.texcoord.y; // Assumes mesh UV maps 0 at bottom and 1 at blade tip

    v.vertex.xyz += _WindDirection.xyz * wave * _WindBendingStrength * heightFactor * heightFactor;
}

// Matrix Code Rain shader (GLSL/WebGL)
uniform float uTime;
uniform vec2 uResolution;
varying vec2 vUv;

float random(float x) {
    return fract(sin(x) * 43758.5453);
}

void main() {
    vec2 st = gl_FragCoord.xy / uResolution.xy;
    st.x *= uResolution.x / uResolution.y;

    float cols = 60.0;
    float colIdx = floor(st.x * cols);
    float speed = 1.0 + random(colIdx) * 3.0;
    float scroll = uTime * speed;

    float cellY = fract(st.y + scroll);
    float character = step(0.3, cellY) * random(floor(st.y * 30.0 + colIdx));

    vec3 rainColor = vec3(0.0, 1.0, 0.2) * cellY * (character > 0.1 ? 1.2 : 0.2);
    gl_FragColor = vec4(rainColor, 1.0);
}

// Curved CRT TV post processing shader with scanlines (GLSL)
uniform sampler2D tDiffuse;
uniform float uTime;
varying vec2 vUv;

vec2 curve(vec2 uv) {
    uv = (uv - 0.5) * 2.0;
    uv.x *= 1.0 + pow((abs(uv.y) / 5.0), 2.0);
    uv.y *= 1.0 + pow((abs(uv.x) / 4.0), 2.0);
    uv = (uv / 2.0) + 0.5;
    return uv;
}

void main() {
    vec2 curvedUv = curve(vUv);
    if (curvedUv.x < 0.0 || curvedUv.x > 1.0 || curvedUv.y < 0.0 || curvedUv.y > 1.0) {
        gl_FragColor = vec4(0.0, 0.0, 0.0, 1.0);
        return;
    }

    // RGB split aberration
    float shift = 0.003;
    float red = texture2D(tDiffuse, curvedUv - vec2(shift, 0.0)).r;
    float green = texture2D(tDiffuse, curvedUv).g;
    float blue = texture2D(tDiffuse, curvedUv + vec2(shift, 0.0)).b;

    vec4 finalColor = vec4(red, green, blue, 1.0);

    // Scanline striping
    float scanline = sin(curvedUv.y * 800.0) * 0.15;
    finalColor.rgb -= scanline;

    gl_FragColor = finalColor;
}

// Procedural Toon Fire Shader utilizing Voronoi math (GLSL)
uniform float uTime;
varying vec2 vUv;

float voronoi(vec2 uv) {
    vec2 p = floor(uv);
    vec2 f = fract(uv);
    float res = 8.0;
    for(int j=-1; j<=1; j++) {
        for(int i=-1; i<=1; i++) {
            vec2 b = vec2(float(i), float(j));
            vec2 r = b - f + fract(sin(p + b) * 43758.5453);
            float d = dot(r,r);
            res = min(res, d);
        }
    }
    return sqrt(res);
}

void main() {
    // Scroll coords upward to simulate fire rising
    vec2 flowUv = vec2(vUv.x, vUv.y - uTime * 1.5);
    float noiseVal = voronoi(flowUv * 3.0);

    // Decay intensity from bottom up
    float gradient = vUv.y;
    float flameShape = saturate((1.0 - gradient * 1.3) - noiseVal * 0.4);

    vec3 color = lerp(vec3(1.0, 0.1, 0.0), vec3(1.0, 0.9, 0.0), flameShape * flameShape);
    gl_FragColor = vec4(color, flameShape);
}

// Vertex Normals Upwards Facing Snow Accumulation (HLSL)
void frag(v2f i, out fixed4 oColor : SV_Target) {
    fixed4 texColor = tex2D(_MainTex, i.uv);
    float3 worldNormal = normalize(i.worldNormal);

    // Snow accumulates primarily on surfaces pointing towards +Y axis (upward)
    float snowLevel = saturate(dot(worldNormal, float3(0, 1, 0)));

    if (snowLevel > _SnowThreshold) {
        float blend = saturate((snowLevel - _SnowThreshold) / (1.0 - _SnowThreshold));
        oColor = lerp(texColor, _SnowColor, blend * _SnowThickness);
    } else {
        oColor = texColor;
    }
}

