using UnityEngine;

public class DungeonGenerator : MonoBehaviour {
    public int width = 50;
    public int height = 50;
    public int roomCount = 10;
    public int minRoomSize = 5;
    public int maxRoomSize = 10;

    private int[,] grid;

    void Start() {
        GenerateDungeon();
    }

    public void GenerateDungeon() {
        grid = new int[width, height];
        // Seed rooms, run basic boundary intersection audits and build linking corridors
        for (int i = 0; i < roomCount; i++) {
            int roomW = Random.Range(minRoomSize, maxRoomSize);
            int roomH = Random.Range(minRoomSize, maxRoomSize);
            int startX = Random.Range(1, width - roomW - 1);
            int startY = Random.Range(1, height - roomH - 1);

            // Paint rooms onto coordinate grid array
            for (int x = startX; x < startX + roomW; x++) {
                for (int y = startY; y < startY + roomH; y++) {
                    grid[x, y] = 1; // Floor tile designation
                }
            }
        }
        Debug.Log("Procedural Dungeon Grid Generated Successfully.");
    }
}

export interface InventoryItem {
  id: string;
  name: string;
  quantity: number;
  maxStack: number;
  weight: number;
}

export class GridInventory {
  private slots: (InventoryItem | null)[] = [];

  constructor(public maxCapacity: number, public weightLimit: number) {
    this.slots = Array(maxCapacity).fill(null);
  }

  public addItem(item: InventoryItem): boolean {
    // Scan for matching stacks to merge, then occupy empty slots
    for (let i = 0; i < this.maxCapacity; i++) {
      const slot = this.slots[i];
      if (slot && slot.id === item.id && slot.quantity < slot.maxStack) {
        const canFit = slot.maxStack - slot.quantity;
        const addition = Math.min(canFit, item.quantity);
        slot.quantity += addition;
        item.quantity -= addition;
        if (item.quantity <= 0) return true;
      }
    }

    if (item.quantity > 0) {
      for (let i = 0; i < this.maxCapacity; i++) {
        if (this.slots[i] === null) {
          this.slots[i] = { ...item };
          return true;
        }
      }
    }
    return false;
  }
}

using UnityEngine;

public class CameraShake : MonoBehaviour {
  private float shakeDuration = 0f;
  private float shakeAmount = 0.7f;
  private float decreaseFactor = 1.0f;
  private Vector3 originalPos;

  void OnEnable() {
    originalPos = transform.localPosition;
  }

  void Update() {
    if (shakeDuration > 0) {
      transform.localPosition = originalPos + Random.insideUnitSphere * shakeAmount;
      shakeDuration -= Time.deltaTime * decreaseFactor;
    } else {
      shakeDuration = 0f;
      transform.localPosition = originalPos;
    }
  }

  public void TriggerShake(float duration, float amount) {
    shakeDuration = duration;
    shakeAmount = amount;
  }
}

