export class ScreenFader {
  private element: HTMLDivElement;
  constructor() {
    this.element = document.createElement('div');
    this.element.style.cssText = 'position:fixed;inset:0;background:black;opacity:0;pointer-events:none;z-index:9999;transition:opacity 0.5s ease;';
    document.body.appendChild(this.element);
  }
  public fadeOut(): Promise<void> {
    this.element.style.pointerEvents = 'all';
    this.element.style.opacity = '1';
    return new Promise(resolve => setTimeout(resolve, 500));
  }
  public fadeIn(): Promise<void> {
    this.element.style.opacity = '0';
    this.element.style.pointerEvents = 'none';
    return new Promise(resolve => setTimeout(resolve, 500));
  }
}

export class DialogueManager {
  private currentLine = 0;
  constructor(private lines: string[], private textElement: HTMLElement) {}

  public typeLine() {
    const text = this.lines[this.currentLine];
    this.textElement.textContent = '';
    let i = 0;
    const interval = setInterval(() => {
      this.textElement.textContent += text[i];
      i++;
      if (i >= text.length) clearInterval(interval);
    }, 40);
  }
}

export class SaveSystem {
  public static save(key: string, data: any): void {
    const str = JSON.stringify(data);
    const encrypted = btoa(unescape(encodeURIComponent(str))); // Base64 packaging
    localStorage.setItem(key, encrypted);
  }
  public static load(key: string): any | null {
    const encrypted = localStorage.getItem(key);
    if (!encrypted) return null;
    try {
      const str = decodeURIComponent(escape(atob(encrypted)));
      return JSON.parse(str);
    } catch (e) {
      return null;
    }
  }
}

export class ParticleEmitter {
  private pool: any[] = [];
  constructor(maxSize = 200) {
    for (let i = 0; i < maxSize; i++) {
      this.pool.push({ x: 0, y: 0, vx: 0, vy: 0, life: 0 });
    }
  }
  public emit(x, y, vx, vy) {
    const particle = this.pool.find(p => p.life <= 0);
    if (particle) {
      particle.x = x; particle.y = y;
      particle.vx = vx; particle.vy = vy;
      particle.life = 1.0;
    }
  }
}

